   486→
   487→func jsonPatchAnnotationValue(configuration, webhook string, patch interface{}) (string, error) {
   488→	p := PatchAuditAnnotation{
   489→		Configuration: configuration,
   490→		Webhook:       webhook,
   491→		Patch:         patch,
